"use client";

import { useSearchParams } from "next/navigation";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { useEffect, useMemo, useState } from "react";
import { ChevronDown } from "lucide-react";

export default function IndustryFormFrequenciesPage() {
  const params = useSearchParams();
  const industry = params.get("industry") || "Industry";
  type Row = { id: number; name: string; discount: number; display: "Both" | "Booking" | "Quote"; isDefault?: boolean };
  const storageKey = useMemo(() => `frequencies_${industry}`, [industry]);
  const [rows, setRows] = useState<Row[]>([]);
  const [status, setStatus] = useState("Active");
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState<Row | null>(null);
  const [form, setForm] = useState<{ name: string; discount: string; display: Row["display"] }>(
    { name: "", discount: "0", display: "Both" }
  );

  useEffect(() => {
    try {
      const stored = JSON.parse(localStorage.getItem(storageKey) || "null");
      if (Array.isArray(stored)) setRows(stored);
      else setRows([
        { id: 9, name: "2x per week", discount: 0, display: "Both" },
        { id: 1, name: "One-Time", discount: 0, display: "Both", isDefault: true },
        { id: 10, name: "Weekly", discount: 15, display: "Both" },
        { id: 11, name: "Every Other Week", discount: 10, display: "Both" },
        { id: 12, name: "Monthly", discount: 5, display: "Both" },
      ]);
    } catch {
      // ignore
    }
  }, [storageKey]);

  useEffect(() => {
    localStorage.setItem(storageKey, JSON.stringify(rows));
  }, [rows, storageKey]);

  const upsert = () => {
    const discount = Number(form.discount) || 0;
    if (!form.name.trim()) return;
    if (editing) {
      setRows(prev => prev.map(r => r.id === editing.id ? { ...r, name: form.name.trim(), discount, display: form.display } : r));
    } else {
      const nextId = (rows.reduce((m, r) => Math.max(m, r.id), 0) || 0) + 1;
      setRows(prev => [...prev, { id: nextId, name: form.name.trim(), discount, display: form.display }]);
    }
    setOpen(false);
    setEditing(null);
    setForm({ name: "", discount: "0", display: "Both" });
  };

  const remove = (id: number) => setRows(prev => prev.filter(r => r.id !== id));
  const makeDefault = (id: number) => setRows(prev => prev.map(r => ({ ...r, isDefault: r.id === id })));
  const move = (id: number, dir: -1 | 1) => setRows(prev => {
    const idx = prev.findIndex(r => r.id === id);
    if (idx < 0) return prev;
    const j = idx + dir;
    if (j < 0 || j >= prev.length) return prev;
    const copy = [...prev];
    const [item] = copy.splice(idx, 1);
    copy.splice(j, 0, item);
    return copy;
  });

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <Select value={status} onValueChange={setStatus}>
          <SelectTrigger className="w-32"><SelectValue placeholder="Status" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="Active">Active</SelectItem>
            <SelectItem value="Inactive">Inactive</SelectItem>
          </SelectContent>
        </Select>
        <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setEditing(null); setForm({ name: "", discount: "0", display: "Both" }); } }}>
          <DialogTrigger asChild>
            <Button variant="outline">Add New</Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{editing ? "Edit Frequency" : "Add Frequency"}</DialogTitle>
            </DialogHeader>
            <div className="grid gap-4">
              <div className="space-y-2">
                <Label htmlFor="freq-name">Frequency</Label>
                <Input id="freq-name" value={form.name} onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))} placeholder="Weekly" />
              </div>
              <div className="space-y-2">
                <Label htmlFor="freq-discount">Discount (%)</Label>
                <Input id="freq-discount" type="number" value={form.discount} onChange={(e) => setForm(p => ({ ...p, discount: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <Label>Display</Label>
                <Select value={form.display} onValueChange={(v: Row["display"]) => setForm(p => ({ ...p, display: v }))}>
                  <SelectTrigger className="w-full"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Both">Both</SelectItem>
                    <SelectItem value="Booking">Booking</SelectItem>
                    <SelectItem value="Quote">Quote</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <DialogFooter>
              <Button onClick={upsert}>Save</Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Frequency</CardTitle>
          <CardDescription>You can add all of the frequencies you accept here. Example weekly services, monthly, etc.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto rounded-md border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Frequency</TableHead>
                  <TableHead>Discount</TableHead>
                  <TableHead>Display</TableHead>
                  <TableHead>Default</TableHead>
                  <TableHead>ID</TableHead>
                  <TableHead className="text-right">Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {rows.map((r) => (
                  <TableRow key={r.id}>
                    <TableCell className="font-medium">{r.name}</TableCell>
                    <TableCell>{r.discount}%</TableCell>
                    <TableCell>{r.display}</TableCell>
                    <TableCell>
                      <Checkbox checked={!!r.isDefault} onCheckedChange={() => makeDefault(r.id)} />
                    </TableCell>
                    <TableCell>{r.id}</TableCell>
                    <TableCell className="text-right">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" size="sm" className="gap-1 text-muted-foreground">Options <ChevronDown className="h-4 w-4" /></Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuItem onClick={() => { setEditing(r); setForm({ name: r.name, discount: String(r.discount), display: r.display }); setOpen(true); }}>Edit</DropdownMenuItem>
                          <DropdownMenuItem onClick={() => move(r.id, -1)}>Move Up</DropdownMenuItem>
                          <DropdownMenuItem onClick={() => move(r.id, 1)}>Move Down</DropdownMenuItem>
                          <DropdownMenuItem onClick={() => remove(r.id)} className="text-red-600">Delete</DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
          <div className="mt-4">
            <Button variant="default" className="text-white" style={{ background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }}>Update Priority</Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
